//! Reverse-mode autograd engine for MLPL.
//!
//! This crate provides a `Tensor` wrapper around `mlpl_array::DenseArray`
//! and a `Tape` that records operations for reverse-mode differentiation.
//!
//! This is the v0.5 scaffold: leaf construction, unique node ids, and a
//! no-op `backward` on a leaf. Operations and gradient propagation land
//! in subsequent steps.

use std::cell::RefCell;
use std::rc::Rc;

use mlpl_array::DenseArray;

/// Opaque identifier for a node on the tape.
#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
pub struct NodeId(pub usize);

/// A node on the tape. For the scaffold step only leaves exist.
#[derive(Debug)]
pub enum Node {
    /// A leaf tensor with no parents.
    Leaf { requires_grad: bool },
}

/// A tape recording the computation graph for reverse-mode autograd.
#[derive(Debug, Default)]
pub struct Tape {
    nodes: RefCell<Vec<Node>>,
}

impl Tape {
    /// Create a fresh empty tape.
    #[must_use]
    pub fn new() -> Rc<Self> {
        Rc::new(Self {
            nodes: RefCell::new(Vec::new()),
        })
    }

    /// Push a node and return its unique id.
    pub fn push(&self, node: Node) -> NodeId {
        let mut nodes = self.nodes.borrow_mut();
        let id = NodeId(nodes.len());
        nodes.push(node);
        id
    }

    /// Number of nodes currently on the tape.
    #[must_use]
    pub fn len(&self) -> usize {
        self.nodes.borrow().len()
    }

    /// Whether the tape is empty.
    #[must_use]
    pub fn is_empty(&self) -> bool {
        self.nodes.borrow().is_empty()
    }
}

/// A differentiable tensor.
///
/// Holds a value, an optional accumulated gradient, a handle to the
/// tape node that produced it, and a `requires_grad` flag.
#[derive(Debug)]
pub struct Tensor {
    value: DenseArray,
    grad: RefCell<Option<DenseArray>>,
    node: NodeId,
    requires_grad: bool,
    tape: Rc<Tape>,
}

impl Tensor {
    /// Construct a leaf tensor on the given tape.
    #[must_use]
    pub fn leaf(tape: Rc<Tape>, value: DenseArray, requires_grad: bool) -> Self {
        let node = tape.push(Node::Leaf { requires_grad });
        Self {
            value,
            grad: RefCell::new(None),
            node,
            requires_grad,
            tape,
        }
    }

    /// Construct a trainable parameter leaf (requires_grad = true).
    #[must_use]
    pub fn param(tape: Rc<Tape>, value: DenseArray) -> Self {
        Self::leaf(tape, value, true)
    }

    /// Borrow the underlying value.
    #[must_use]
    pub fn value(&self) -> &DenseArray {
        &self.value
    }

    /// Borrow the accumulated gradient, if any.
    #[must_use]
    pub fn grad(&self) -> std::cell::Ref<'_, Option<DenseArray>> {
        self.grad.borrow()
    }

    /// Whether this tensor participates in gradient tracking.
    #[must_use]
    pub fn requires_grad(&self) -> bool {
        self.requires_grad
    }

    /// The tape node id that produced this tensor.
    #[must_use]
    pub fn node(&self) -> NodeId {
        self.node
    }

    /// Reverse-mode backward pass from this tensor.
    ///
    /// For the scaffold this is a no-op on leaves. Non-leaf behavior is
    /// introduced in later steps as operations are added to the tape.
    pub fn backward(&self) {
        let nodes = self.tape.nodes.borrow();
        if let Some(Node::Leaf { .. }) = nodes.get(self.node.0) {
            // Leaves have no parents; nothing to propagate.
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use mlpl_array::DenseArray;

    #[test]
    fn construct_param_tensor() {
        let tape = Tape::new();
        let t = Tensor::param(tape.clone(), DenseArray::from_scalar(3.0));
        assert!(t.requires_grad());
        assert_eq!(t.value().data(), &[3.0]);
        assert!(t.grad().is_none());
        assert_eq!(tape.len(), 1);
    }

    #[test]
    fn leaf_non_trainable() {
        let tape = Tape::new();
        let t = Tensor::leaf(tape, DenseArray::from_vec(vec![1.0, 2.0]), false);
        assert!(!t.requires_grad());
        assert_eq!(t.value().data(), &[1.0, 2.0]);
    }

    #[test]
    fn backward_on_leaf_is_noop() {
        let tape = Tape::new();
        let t = Tensor::param(tape, DenseArray::from_scalar(1.0));
        t.backward();
        assert!(t.grad().is_none());
    }

    #[test]
    fn node_ids_are_unique() {
        let tape = Tape::new();
        let a = Tensor::param(tape.clone(), DenseArray::from_scalar(1.0));
        let b = Tensor::param(tape.clone(), DenseArray::from_scalar(2.0));
        let c = Tensor::leaf(tape.clone(), DenseArray::from_scalar(3.0), false);
        assert_ne!(a.node(), b.node());
        assert_ne!(b.node(), c.node());
        assert_ne!(a.node(), c.node());
        assert_eq!(tape.len(), 3);
    }

    #[test]
    fn fresh_tape_is_empty() {
        let tape = Tape::new();
        assert!(tape.is_empty());
    }
}

