//! Differentiable tensor wrapper.

use std::rc::Rc;

use mlpl_array::DenseArray;

use crate::backward;
use crate::ops::{BinaryOp, UnaryOp};
use crate::tape::{NodeData, NodeId, NodeKind, Tape};

/// A differentiable tensor: a handle into a [`Tape`] node.
#[derive(Debug, Clone)]
pub struct Tensor {
    node: NodeId,
    tape: Rc<Tape>,
}

impl Tensor {
    /// Construct a leaf tensor on `tape`.
    #[must_use]
    pub fn leaf(tape: Rc<Tape>, value: DenseArray, requires_grad: bool) -> Self {
        let node = tape.push(NodeData {
            value,
            grad: None,
            kind: NodeKind::Leaf,
            requires_grad,
        });
        Self { node, tape }
    }

    /// Construct a trainable parameter leaf (`requires_grad` = true).
    #[must_use]
    pub fn param(tape: Rc<Tape>, value: DenseArray) -> Self {
        Self::leaf(tape, value, true)
    }

    /// Clone the tape handle.
    #[must_use]
    pub fn tape(&self) -> Rc<Tape> {
        Rc::clone(&self.tape)
    }

    /// Node id on the tape.
    #[must_use]
    pub fn node(&self) -> NodeId {
        self.node
    }

    /// Clone of the forward value.
    #[must_use]
    pub fn value(&self) -> DenseArray {
        self.tape.nodes()[self.node.0].value.clone()
    }

    /// Clone of the accumulated gradient, if any.
    #[must_use]
    pub fn grad(&self) -> Option<DenseArray> {
        self.tape.nodes()[self.node.0].grad.clone()
    }

    /// Whether this node is a trainable leaf.
    #[must_use]
    pub fn requires_grad(&self) -> bool {
        self.tape.nodes()[self.node.0].requires_grad
    }

    fn unary(&self, op: UnaryOp) -> Self {
        let x = self.value();
        let y = op.forward(&x);
        let node = self.tape.push(NodeData {
            value: y,
            grad: None,
            kind: NodeKind::Unary {
                op,
                parent: self.node,
            },
            requires_grad: false,
        });
        Self {
            node,
            tape: Rc::clone(&self.tape),
        }
    }

    fn binary(&self, other: &Self, op: BinaryOp) -> Self {
        let a = self.value();
        let b = other.value();
        let v = op.forward(&a, &b).expect("broadcastable shapes");
        let node = self.tape.push(NodeData {
            value: v,
            grad: None,
            kind: NodeKind::Binary {
                op,
                left: self.node,
                right: other.node,
            },
            requires_grad: false,
        });
        Self {
            node,
            tape: Rc::clone(&self.tape),
        }
    }

    /// Elementwise addition.
    #[must_use]
    pub fn add(&self, other: &Self) -> Self {
        self.binary(other, BinaryOp::Add)
    }

    /// Elementwise subtraction.
    #[must_use]
    pub fn sub(&self, other: &Self) -> Self {
        self.binary(other, BinaryOp::Sub)
    }

    /// Elementwise multiplication.
    #[must_use]
    pub fn mul(&self, other: &Self) -> Self {
        self.binary(other, BinaryOp::Mul)
    }

    /// Elementwise division.
    #[must_use]
    pub fn div(&self, other: &Self) -> Self {
        self.binary(other, BinaryOp::Div)
    }

    /// Elementwise negation.
    #[must_use]
    pub fn neg(&self) -> Self {
        self.unary(UnaryOp::Neg)
    }

    /// Elementwise exponential.
    #[must_use]
    pub fn exp(&self) -> Self {
        self.unary(UnaryOp::Exp)
    }

    /// Elementwise natural log.
    #[must_use]
    pub fn log(&self) -> Self {
        self.unary(UnaryOp::Log)
    }

    /// Elementwise ReLU.
    #[must_use]
    pub fn relu(&self) -> Self {
        self.unary(UnaryOp::Relu)
    }

    /// Elementwise tanh.
    #[must_use]
    pub fn tanh(&self) -> Self {
        self.unary(UnaryOp::Tanh)
    }

    /// Elementwise sigmoid.
    #[must_use]
    pub fn sigmoid(&self) -> Self {
        self.unary(UnaryOp::Sigmoid)
    }

    /// Run reverse-mode backward from this tensor.
    pub fn backward(&self) {
        backward::backward(&self.tape, self.node);
    }
}

