//! Finite-difference gradcheck for elementwise ops.

use mlpl_array::DenseArray;
use mlpl_autograd::{Tape, Tensor};

const EPS: f64 = 1e-6;
const TOL: f64 = 1e-4;

/// Numerically differentiate `f(x)` wrt every element of `x`, using
/// central differences. Returns a `DenseArray` shaped like `x`.
fn fd_grad<F>(x: &DenseArray, f: F) -> DenseArray
where
    F: Fn(&DenseArray) -> f64,
{
    let n = x.data().len();
    let mut out = vec![0.0; n];
    for i in 0..n {
        let mut plus = x.data().to_vec();
        let mut minus = x.data().to_vec();
        plus[i] += EPS;
        minus[i] -= EPS;
        let fp = f(&DenseArray::new(x.shape().clone(), plus).unwrap());
        let fm = f(&DenseArray::new(x.shape().clone(), minus).unwrap());
        out[i] = (fp - fm) / (2.0 * EPS);
    }
    DenseArray::new(x.shape().clone(), out).unwrap()
}

fn sum(t: &Tensor) -> f64 {
    t.value().data().iter().sum()
}

fn assert_close(a: &DenseArray, b: &DenseArray) {
    assert_eq!(a.shape(), b.shape(), "shape mismatch {a:?} vs {b:?}");
    for (x, y) in a.data().iter().zip(b.data().iter()) {
        assert!((x - y).abs() < TOL, "grad mismatch: {x} vs {y}");
    }
}

/// Run gradcheck on a unary op. `apply` builds the forward expression.
fn check_unary(x_data: Vec<f64>, apply: fn(&Tensor) -> Tensor) {
    let x_arr = DenseArray::from_vec(x_data);
    let tape = Tape::new();
    let x = Tensor::param(tape, x_arr.clone());
    let y = apply(&x);
    // Scalar loss = sum(y); backward gives d(sum(y))/dx.
    let loss_grad_input = DenseArray::from_vec(vec![1.0; x_arr.data().len()]);
    // Seed the output with ones to emulate d(sum)/d(y) = 1, since the
    // current engine does not have a sum op yet.
    {
        let mut nodes = y.tape().nodes_mut();
        nodes[y.node().0].grad = Some(
            DenseArray::new(y.value().shape().clone(), vec![1.0; y.value().data().len()]).unwrap(),
        );
    }
    // Manually walk backward without reseeding.
    mlpl_autograd::backward::backward_no_seed(&y.tape(), y.node());
    let ag = x.grad().expect("grad");
    let num = fd_grad(&x_arr, |xv| {
        let tape = Tape::new();
        let t = Tensor::leaf(tape, xv.clone(), false);
        let out = apply(&t);
        out.value().data().iter().sum()
    });
    assert_close(&ag, &num);
    // also sanity check loss_grad_input size
    assert_eq!(loss_grad_input.data().len(), x.value().data().len());
}

/// Run gradcheck on a binary op.
fn check_binary(
    a_data: Vec<f64>,
    b_data: Vec<f64>,
    apply: fn(&Tensor, &Tensor) -> Tensor,
) {
    let a_arr = DenseArray::from_vec(a_data);
    let b_arr = DenseArray::from_vec(b_data);
    let tape = Tape::new();
    let a = Tensor::param(tape.clone(), a_arr.clone());
    let b = Tensor::param(tape, b_arr.clone());
    let y = apply(&a, &b);
    {
        let mut nodes = y.tape().nodes_mut();
        nodes[y.node().0].grad = Some(
            DenseArray::new(y.value().shape().clone(), vec![1.0; y.value().data().len()]).unwrap(),
        );
    }
    mlpl_autograd::backward::backward_no_seed(&y.tape(), y.node());
    let ga = a.grad().expect("ga");
    let gb = b.grad().expect("gb");
    let num_a = fd_grad(&a_arr, |av| {
        let tape = Tape::new();
        let at = Tensor::leaf(tape.clone(), av.clone(), false);
        let bt = Tensor::leaf(tape, b_arr.clone(), false);
        sum(&apply(&at, &bt))
    });
    let num_b = fd_grad(&b_arr, |bv| {
        let tape = Tape::new();
        let at = Tensor::leaf(tape.clone(), a_arr.clone(), false);
        let bt = Tensor::leaf(tape, bv.clone(), false);
        sum(&apply(&at, &bt))
    });
    assert_close(&ga, &num_a);
    assert_close(&gb, &num_b);
}

